import { useState } from "react";
import { MarketingCarousel } from "@/components/marketing-carousel";
import { createFileRoute } from "@tanstack/react-router";
import { AnedotTypemarkIcon, Button } from "@workspace/ui";
import { Loader2 } from "lucide-react";
import { initiateLogin, redirectIfAuthenticated } from "./-auth";

export const Route = createFileRoute("/login")({
  loader: () => redirectIfAuthenticated(),
  validateSearch: (search: Record<string, unknown>): { error?: string } => ({
    error: typeof search.error === "string" ? search.error : undefined,
  }),
  component: LoginPage,
});

function LoginPage() {
  const { error } = Route.useSearch();
  const [loading, setLoading] = useState(false);

  const handleContinue = async () => {
    setLoading(true);
    await initiateLogin();
  };

  return (
    <div className="mx-auto flex min-h-screen max-w-6xl font-outfit">
      <div className="flex flex-1 basis-1/2 flex-col pt-10 pl-14">
        <AnedotTypemarkIcon size={120} className="text-secondary-600" />
        <MarketingCarousel />
      </div>

      <div className="flex flex-1 basis-1/2 items-center justify-center overflow-auto px-6 py-10">
        <div className="w-full max-w-100">
          <div className="mb-8">
            <h1 className="mb-1.5 font-bold text-2xl text-foreground">
              Welcome back
            </h1>
            <p className="text-muted-foreground text-sm">
              Continue to the secure Anedot sign-in experience
            </p>
          </div>

          {error && (
            <div className="mb-4 rounded-md border border-destructive/20 bg-destructive/10 p-3 text-destructive text-sm">
              {error === "state_mismatch"
                ? "Invalid session state. Please try again."
                : error}
            </div>
          )}

          <div className="rounded-2xl border-2 border-border bg-card p-7 shadow-sm">
            <p className="text-muted-foreground text-sm leading-6">
              Sign-in, password recovery, multi-factor authentication, and
              account creation are all handled in the dedicated auth app.
            </p>

            <Button
              type="button"
              className="mt-6 h-10 w-full"
              onClick={handleContinue}
              disabled={loading}
            >
              {loading && <Loader2 className="animate-spin" size={16} />}
              {loading ? "Redirecting..." : "Continue to Sign In"}
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

