import { createEnv } from "@t3-oss/env-core";
import { z } from "zod";

export const env = createEnv({
  server: {
    API_HOSTNAME: z.url(),
    SESSION_SECRET: z.uuidv4(),
    MOCK_ACCESS_TOKEN: z.uuidv4(),
  },
  clientPrefix: "VITE_",
  client: {
    VITE_TEMP_BYPASS_AUTH: z.stringbool(),
    VITE_ENABLE_RMP: z.stringbool(),
    VITE_ROLLBAR_ACCESS_TOKEN: z.string(),
    VITE_AUTH_APP_URL: z.url(),
  },
  runtimeEnv: process.env,
  emptyStringAsUndefined: true,
  skipValidation: typeof window !== "undefined",
  onValidationError: (issues) => {
    const formatted = issues
      .map((issue) => {
        const path = issue.path
          ?.map((p) => (typeof p === "object" ? p.key : p))
          .join(".");
        return path ? `  - ${path}: ${issue.message}` : `  - ${issue.message}`;
      })
      .join("\n");
    throw new Error(`Invalid environment variables:\n${formatted}`);
  },
});

