import { createHmac } from "node:crypto";
import { CognitoIdentityProviderClient } from "@aws-sdk/client-cognito-identity-provider";
import { getCognitoConfig } from "./env";

let client: CognitoIdentityProviderClient | null = null;

export function getCognitoClient() {
  if (!client) {
    const { region } = getCognitoConfig();
    client = new CognitoIdentityProviderClient({ region });
  }
  return client;
}

export function secretHash(username: string): string | undefined {
  const { clientId, clientSecret } = getCognitoConfig();
  if (!clientSecret) return undefined;
  return createHmac("sha256", clientSecret)
    .update(username + clientId)
    .digest("base64");
}

import { useSession } from "@tanstack/react-start/server";
import { getSessionSecret } from "./env";

export type OauthRequestState = {
  clientId: string;
  identityProvider?: "Google";
  redirectUri: string;
  responseType: "code";
  scope: string;
  state: string;
};

export type TransactionState = {
  challengeName?: "NEW_PASSWORD_REQUIRED" | "SMS_MFA" | "SOFTWARE_TOKEN_MFA";
  challengeSession?: string;
  challengeUsername?: string;
  oauthRequest?: OauthRequestState;
  pendingResetEmail?: string;
  pendingSignupEmail?: string;
};

export async function useTransactionSession() {
  return useSession<TransactionState>({
    name: "anedot-auth-tx",
    password: getSessionSecret(),
    cookie: {
      httpOnly: true,
      path: "/",
      sameSite: "lax",
      secure: process.env.NODE_ENV === "production",
    },
  });
}

export async function useMockAuthSession() {
  return useSession<{ authenticated?: boolean; userEmail?: string }>({
    name: "anedot-auth-mock-session",
    password: getSessionSecret(),
    cookie: {
      httpOnly: true,
      path: "/",
      sameSite: "lax",
      secure: process.env.NODE_ENV === "production",
    },
  });
}

