import { getCognitoClient, secretHash } from "@/lib/cognito";
import { signInWithSrp } from "@/lib/cognito-srp";
import {
  getCognitoConfig,
  isAllowedClientUri,
  isMockAuthEnabled,
} from "@/lib/env";
import { useMockAuthSession, useTransactionSession } from "@/lib/session";
import { randomUUID } from "node:crypto";
import {
  ConfirmForgotPasswordCommand,
  ConfirmSignUpCommand,
  ForgotPasswordCommand,
  ResendConfirmationCodeCommand,
  RespondToAuthChallengeCommand,
  SignUpCommand,
} from "@aws-sdk/client-cognito-identity-provider";
import { isRedirect, redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import {
  authorizeSearchSchema,
  challengeInputSchema,
  confirmSignUpInputSchema,
  forgotPasswordInputSchema,
  logoutSearchSchema,
  resetPasswordInputSchema,
  signInInputSchema,
  signUpInputSchema,
} from "./contracts";
import { buildClientRedirect } from "./redirects";

type AuthResult = { error?: string; ok?: boolean };

export function rethrowIfRedirect(err: unknown): void {
  if (isRedirect(err)) throw err;
}

function requireOauthRequest(
  sessionData: Awaited<ReturnType<typeof useTransactionSession>>["data"],
) {
  const request = sessionData.oauthRequest;
  if (!request) {
    throw redirect({
      to: "/error",
      search: { reason: "missing_auth_context" },
    });
  }
  return request;
}

function cognitoAuthorizeUrl(search: Record<string, string>) {
  const cognito = getCognitoConfig();
  if (!cognito.domain) {
    return null;
  }

  const authorize = new URL("/oauth2/authorize", cognito.domain);
  for (const [key, value] of Object.entries(search)) {
    authorize.searchParams.set(key, value);
  }
  return authorize.toString();
}

function redirectThroughCognito(
  oauthRequest: ReturnType<typeof requireOauthRequest>,
): never {
  const url = cognitoAuthorizeUrl({
    client_id: oauthRequest.clientId,
    redirect_uri: oauthRequest.redirectUri,
    response_type: oauthRequest.responseType,
    scope: oauthRequest.scope,
    state: oauthRequest.state,
    ...(oauthRequest.identityProvider
      ? { identity_provider: oauthRequest.identityProvider }
      : {}),
  });

  if (!url) {
    throw redirect({
      to: "/error",
      search: { reason: "missing_cognito_domain" },
    });
  }

  throw redirect({ href: url });
}

function cognitoErrorMessage(err: unknown): string {
  if (err instanceof Error) {
    switch (err.name) {
      case "NotAuthorizedException":
        return "Incorrect email or password.";
      case "UserNotFoundException":
        return "Incorrect email or password.";
      case "UserNotConfirmedException":
        return "Please confirm your account before signing in.";
      case "PasswordResetRequiredException":
        return "A password reset is required.";
      case "CodeMismatchException":
        return "Invalid verification code.";
      case "ExpiredCodeException":
        return "Verification code has expired. Please request a new one.";
      case "UsernameExistsException":
        return "An account with this email already exists.";
      case "InvalidPasswordException":
        return err.message;
      case "LimitExceededException":
      case "TooManyRequestsException":
        return "Too many attempts. Please try again later.";
      default:
        return "An unexpected error occurred.";
    }
  }
  return "An unexpected error occurred.";
}

export const beginAuthorizeFn = createServerFn({ method: "GET" })
  .inputValidator(authorizeSearchSchema)
  .handler(async ({ data }) => {
    if (!isAllowedClientUri(data.client_id, data.redirect_uri)) {
      throw redirect({
        to: "/error",
        search: { reason: "invalid_redirect_uri" },
      });
    }

    const txSession = await useTransactionSession();
    await txSession.update({
      oauthRequest: {
        clientId: data.client_id,
        identityProvider: data.identity_provider,
        redirectUri: data.redirect_uri,
        responseType: data.response_type,
        scope: data.scope,
        state: data.state,
      },
    });

    if (data.identity_provider && !isMockAuthEnabled()) {
      const url = cognitoAuthorizeUrl({
        client_id: data.client_id,
        identity_provider: data.identity_provider,
        redirect_uri: data.redirect_uri,
        response_type: data.response_type,
        scope: data.scope,
        state: data.state,
      });
      if (!url) {
