function cognitoAuthorizeUrl(search: Record<string, string>) {
  const cognito = getCognitoConfig();
  if (!cognito.domain) {
    return null;
  }

  const authorize = new URL("/oauth2/authorize", cognito.domain);
  for (const [key, value] of Object.entries(search)) {
    authorize.searchParams.set(key, value);
