  }
}

function parseJsonObject(raw: string): Record<string, unknown> | null {
  const tryParseObject = (value: string): Record<string, unknown> | null => {
    const parsed = JSON.parse(value);
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      return parsed as Record<string, unknown>;
    }

    // Cloudflare dev vars may deliver escaped JSON strings.
    if (typeof parsed === "string") {
      const reparsed = JSON.parse(parsed);
      if (
        reparsed &&
        typeof reparsed === "object" &&
        !Array.isArray(reparsed)
      ) {
        return reparsed as Record<string, unknown>;
      }
    }
    return null;
  };

  try {
    const parsed = tryParseObject(raw);
    if (parsed) {
      return parsed;
    }
  } catch {
    // Try additional formats below.
  }

  // Wrangler can pass escaped JSON without wrapping quotes: {\"k\":\"v\"}
  try {
    const normalized = raw.replace(/\\"/g, '"');
    const parsed = tryParseObject(normalized);
    if (parsed) {
      return parsed;
    }
  } catch {
    // Ignore malformed JSON.
  }
  return null;
}

function parseAllowedUrisByClientId(): ClientUriAllowlist {
  const raw = process.env.AUTH_ALLOWED_URIS_BY_CLIENT_ID;
  if (!raw) {
    return new Map();
  }

  const parsed = parseJsonObject(raw);
  if (!parsed) {
    return new Map();
  }

  const allowlist = new Map<string, Set<string>>();
  for (const [clientId, uris] of Object.entries(parsed)) {
    if (!Array.isArray(uris)) {
      continue;
    }
    const normalizedUris = new Set<string>();
    for (const uri of uris) {
      if (typeof uri !== "string") {
        continue;
      }
      const normalized = normalizeUri(uri);
      if (normalized) {
        normalizedUris.add(normalized);
      }
    }
    allowlist.set(clientId, normalizedUris);
  }
  return allowlist;
}

export function isAllowedClientUri(clientId: string, uri: string) {
  const normalized = normalizeUri(uri);
  if (!normalized) {
    return false;
  }

  const allowlist = parseAllowedUrisByClientId();
  const allowedUris = allowlist.get(clientId);
  if (!allowedUris || allowedUris.size === 0) {
    return false;
  }

  return allowedUris.has(normalized);
}

export function getSessionSecret() {
  const secret = process.env.AUTH_SESSION_SECRET?.trim();

  if (!secret) {
    throw new Error(
      "Missing AUTH_SESSION_SECRET. Set a strong secret (at least 32 characters).",
    );
  }

  if (secret === "dev-only-session-secret-change-me") {
    throw new Error(
      "Insecure AUTH_SESSION_SECRET value detected. Generate and set a unique secret.",
    );
  }

  if (secret.length < 32) {
    throw new Error("AUTH_SESSION_SECRET must be at least 32 characters long.");
  }

  return secret;
}

export function getCognitoConfig() {
  return {
    clientId: process.env.COGNITO_CLIENT_ID ?? "",
    clientSecret: process.env.COGNITO_CLIENT_SECRET ?? "",
    domain: process.env.COGNITO_DOMAIN ?? "",
    region: process.env.COGNITO_REGION ?? "us-west-2",
    userPoolId: process.env.COGNITO_USER_POOL_ID ?? "",
  };
}

