import { createHash, createHmac, randomBytes } from "node:crypto";
import {
  InitiateAuthCommand,
  type InitiateAuthCommandOutput,
  RespondToAuthChallengeCommand,
  type RespondToAuthChallengeCommandOutput,
} from "@aws-sdk/client-cognito-identity-provider";
import { getCognitoClient, secretHash } from "./cognito";
import { getCognitoConfig } from "./env";

// SRP group parameters used by Cognito.
// N is the 2048-bit MODP prime (Group 14), g is generator 2:
// https://www.rfc-editor.org/rfc/rfc3526#section-3
// Cognito's JS helper uses this same N/g pair:
// https://github.com/amazon-archives/amazon-cognito-identity-js/blob/master/src/AuthenticationHelper.js
const N_HEX =
  "FFFFFFFFFFFFFFFFC90FDAA22168C234C4C6628B80DC1CD1" +
  "29024E088A67CC74020BBEA63B139B22514A08798E3404DD" +
  "EF9519B3CD3A431B302B0A6DF25F14374FE1356D6D51C245" +
  "E485B576625E7EC6F44C42E9A637ED6B0BFF5CB6F406B7ED" +
  "EE386BFB5A899FA5AE9F24117C4B1FE649286651ECE45B3D" +
  "C2007CB8A163BF0598DA48361C55D39A69163FA8FD24CF5F" +
  "83655D23DCA3AD961C62F356208552BB9ED529077096966D" +
  "670C354E4ABC9804F1746C08CA18217C32905E462E36CE3B" +
  "E39E772C180E86039B2783A2EC07A28FB5C55DF06F4C52C9" +
  "DE2BCBF6955817183995497CEA956AE515D2261898FA0510" +
  "15728E5A8AACAA68FFFFFFFFFFFFFFFF";
const G_HEX = "2";
const INFO_BITS = "Caldera Derived Key";
const N_BIGINT = hexToBigInt(N_HEX);
const G_BIGINT = hexToBigInt(G_HEX);
// SRP multiplier k = H(padHex(N) || padHex(g)).
// Using toPaddedHex for both values keeps us aligned with Cognito helper behavior.
const K_BIGINT = hexToBigInt(
  hashHex(`${toPaddedHex(N_BIGINT)}${toPaddedHex(G_BIGINT)}`),
);

type CognitoAuthResult =
  | InitiateAuthCommandOutput
  | RespondToAuthChallengeCommandOutput;

export async function signInWithSrp(
  username: string,
  password: string,
): Promise<CognitoAuthResult> {
  const { clientId, userPoolId } = getCognitoConfig();
  const poolName = parsePoolName(userPoolId);
  const smallA = randomSmallAValue();
  const largeA = calculateLargeAValue(smallA);
  const signInSecretHash = secretHash(username);

  const initiateResponse = await getCognitoClient().send(
    new InitiateAuthCommand({
      AuthFlow: "USER_SRP_AUTH",
      AuthParameters: {
        USERNAME: username,
        SRP_A: toPaddedHex(largeA),
        ...(signInSecretHash ? { SECRET_HASH: signInSecretHash } : {}),
      },
      ClientId: clientId,
    }),
  );

  if (initiateResponse.ChallengeName !== "PASSWORD_VERIFIER") {
    return initiateResponse;
  }

  const challengeParameters = initiateResponse.ChallengeParameters;
  if (!challengeParameters) {
    throw new Error("Cognito SRP challenge parameters are missing.");
  }

  const srpBHex = challengeParameters.SRP_B;
  const saltHex = challengeParameters.SALT;
  const secretBlock = challengeParameters.SECRET_BLOCK;
  const userIdForSrp = challengeParameters.USER_ID_FOR_SRP ?? username;
  if (!srpBHex || !saltHex || !secretBlock) {
    throw new Error("Cognito SRP challenge parameters are incomplete.");
  }

  const timestamp = utcTimestamp();
  const signature = calculatePasswordClaimSignature({
    password,
    poolName,
    saltHex,
    secretBlock,
    largeA,
    smallA,
    srpBHex,
    timestamp,
    userIdForSrp,
  });
  const challengeSecretHash = secretHash(userIdForSrp);

  return getCognitoClient().send(
    new RespondToAuthChallengeCommand({
