function hexToBigInt(hex: string): bigint {
  return BigInt(`0x${hex}`);
}

function modPow(base: bigint, exponent: bigint, modulus: bigint): bigint {
  if (modulus === 1n) {
    return 0n;
  }
  let result = 1n;
  let runningBase = base % modulus;
  let runningExponent = exponent;
  while (runningExponent > 0n) {
    if (runningExponent % 2n === 1n) {
      result = (result * runningBase) % modulus;
    }
    runningExponent >>= 1n;
    runningBase = (runningBase * runningBase) % modulus;
  }
  return result;
}

function utcTimestamp(): string {
  const now = new Date();
  const day = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"][
    now.getUTCDay()
  ];
  const month = [
    "Jan",
    "Feb",
    "Mar",
    "Apr",
    "May",
    "Jun",
    "Jul",
    "Aug",
    "Sep",
    "Oct",
    "Nov",
    "Dec",
  ][now.getUTCMonth()];
  const date = now.getUTCDate();
  const hour = String(now.getUTCHours()).padStart(2, "0");
  const minute = String(now.getUTCMinutes()).padStart(2, "0");
  const second = String(now.getUTCSeconds()).padStart(2, "0");
  const year = now.getUTCFullYear();
  return `${day} ${month} ${date} ${hour}:${minute}:${second} UTC ${year}`;
}

