import { getMockApiUrls } from "./get-mock-api-urls";
import { expect, test } from "./test-fixture";

const urls = getMockApiUrls();

const mockUser = {
  id: 1,
  email: "test@example.com",
  cognito_sub: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

const mockOrgTenant = {
  id: 42,
  tenant_type: "org" as const,
  name: "Hope Foundation",
  org_id: "org-42",
  vendor_id: null,
  created_at: "2024-01-01T00:00:00Z",
  updated_at: "2024-01-01T00:00:00Z",
};

test("sidebar shows empty state when the user has no tenants", async ({
  page,
  mockServerRequest,
}) => {
  await mockServerRequest.GET(urls.usersMe, { body: mockUser });
  await mockServerRequest.GET(urls.tenants, { body: [] });

  // Users without a tenant are redirected to /organizations/new, which still
  // renders the AppSidebar inside the _authed layout.
  await page.goto("/organizations/new");

  await expect(page.getByText("No tenants yet")).toBeVisible();
  await expect(
    page.getByRole("button", { name: /Switch organization/i }),
  ).toHaveCount(0);
});

