import type { Tenant } from "@/types/bootstrap";
import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";
import {
  readUserSession,
  type UserSession,
  writeUserSession,
} from "./user-session.server";

const userSessionUpdateSchema = z.object({
  selectedTenantId: z.number().int().nullable().optional(),
  theme: z.enum(["light", "dark", "system"]).optional(),
});

export const getUserSession = createServerFn({ method: "GET" }).handler(
  async (): Promise<UserSession> => {
    return readUserSession();
  },
);

export const updateUserSession = createServerFn({ method: "POST" })
  .inputValidator(userSessionUpdateSchema)
  .handler(async ({ data }): Promise<UserSession> => {
    return writeUserSession(data);
  });

export function pickSelectedTenantId(
  tenants: Tenant[],
  storedTenantId: number | null,
): number | null {
  if (tenants.length === 0) {
    return null;
  }
  if (
    storedTenantId !== null &&
    tenants.some((tenant) => tenant.id === storedTenantId)
  ) {
    return storedTenantId;
  }
  const mostRecent = tenants.reduce((latest, tenant) =>
    tenant.updated_at > latest.updated_at ? tenant : latest,
  );
  return mostRecent.id;
}

export async function resolveSelectedTenantId(
  tenants: Tenant[],
): Promise<number | null> {
  const session = await getUserSession();
  const picked = pickSelectedTenantId(tenants, session.selectedTenantId);
  if (picked !== null && picked !== session.selectedTenantId) {
    await updateUserSession({ data: { selectedTenantId: picked } });
  }
  return picked;
}

export type { Theme, UserSession } from "./user-session.server";

import { env } from "@/env";
import { createServerOnlyFn } from "@tanstack/react-start";
import { useSession } from "@tanstack/react-start/server";

const isSecure = import.meta.env.MODE === "production";

export type Theme = "light" | "dark" | "system";

export type UserSession = {
  selectedTenantId: number | null;
  theme: Theme;
};

export const USER_SESSION_DEFAULTS: UserSession = {
  selectedTenantId: null,
  theme: "system",
};

export const useUserSessionStore = createServerOnlyFn(() => {
  return useSession<Partial<UserSession>>({
    password: env.SESSION_SECRET,
    name: "userSession",
    cookie: {
      httpOnly: true,
      sameSite: "lax",
      secure: isSecure,
      maxAge: 3600 * 24 * 365,
      path: "/",
    },
  });
});

export const readUserSession = createServerOnlyFn(
  async (): Promise<UserSession> => {
    const store = await useUserSessionStore();
    return {
      selectedTenantId:
        typeof store.data.selectedTenantId === "number"
          ? store.data.selectedTenantId
          : USER_SESSION_DEFAULTS.selectedTenantId,
      theme: isTheme(store.data.theme)
        ? store.data.theme
        : USER_SESSION_DEFAULTS.theme,
    };
  },
);

export const writeUserSession = createServerOnlyFn(
  async (update: Partial<UserSession>): Promise<UserSession> => {
    const store = await useUserSessionStore();
    await store.update(update);
    return await readUserSession();
  },
);

function isTheme(value: unknown): value is Theme {
  return value === "light" || value === "dark" || value === "system";
}

